import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Tooltip } from "react-leaflet";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip as ChartTooltip, Legend, ResponsiveContainer } from "recharts";
import "leaflet/dist/leaflet.css";

export default function BusMap() {
  const [buses, setBuses] = useState([]);
  const [chartVisible, setChartVisible] = useState(false);
  const [history, setHistory] = useState([]);

  // Fetch bus data every 2 minutes
  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const res = await fetch("http://127.0.0.1:8000/buses");
        const data = await res.json();
        const currentBuses = data.buses || [];
        setBuses(currentBuses);

        // Update history for chart
        const runningCount = currentBuses.filter((b) => b.status === "Running").length;
        const ghostCount = currentBuses.filter((b) => b.status === "Ghost").length;
        const anomalyCount = currentBuses.filter((b) => b.status === "Anomaly").length;

        setHistory((prev) => [
          ...prev,
          {
            time: new Date().toLocaleTimeString(),
            Running: runningCount,
            Ghost: ghostCount,
            Anomaly: anomalyCount,
          },
        ]);
      } catch (err) {
        console.error("Failed to fetch bus data:", err);
      }
    };

    fetchBuses(); // initial fetch
    const interval = setInterval(fetchBuses, 2 * 60 * 1000); // every 2 min

    return () => clearInterval(interval);
  }, []);

  return (
    <div style={{ height: "100vh", width: "100%", position: "relative" }}>
      {/* Bus counts + Chart button */}
      <div
        style={{
          position: "absolute",
          top: 12,
          left: 50,
          background: "rgba(255,255,255,0.95)",
          padding: "8px 12px",
          borderRadius: "8px",
          boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
          zIndex: 1000,
          fontSize: "14px",
          display: "flex",
          alignItems: "center",
          gap: "12px",
        }}
      >
        <div>
          🟢 Running: {buses.filter((b) => b.status === "Running").length} <br />
          🔴 Ghost: {buses.filter((b) => b.status === "Ghost").length} <br />
          🟠 Anomaly: {buses.filter((b) => b.status === "Anomaly").length}
        </div>
        <button
          onClick={() => setChartVisible((prev) => !prev)}
          style={{
            padding: "6px 10px",
            borderRadius: "6px",
            border: "none",
            cursor: "pointer",
            backgroundColor: "#007bff",
            color: "#fff",
          }}
        >
          {chartVisible ? "Hide Chart" : "Show Chart"}
        </button>
      </div>

      {/* Map */}
      <MapContainer
        center={[40.7128, -74.006]}
        zoom={12}
        style={{ height: "100%", width: "100%" }}
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a>'
          url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
          subdomains={["a", "b", "c", "d"]}
        />

        {buses.map((bus, index) => (
          <CircleMarker
            key={`${bus.feed}-${bus.id}-${index}`}
            center={[bus.lat, bus.lon]}
            radius={6}
            fillOpacity={1}
            color={
              bus.status === "Running"
                ? "green"
                : bus.status === "Ghost"
                ? "red"
                : "orange"
            }
          >
            <Tooltip>
              <div>
                <strong>Bus ID:</strong> {bus.id} <br />
                <strong>Feed:</strong> {bus.feed} <br />
                <strong>Status:</strong> {bus.status} <br />
                <strong>Speed:</strong>{" "}
                {bus.speed ? bus.speed.toFixed(1) + " mph" : "N/A"}
              </div>
            </Tooltip>
          </CircleMarker>
        ))}
      </MapContainer>

      {/* Chart overlay */}
      {chartVisible && (
        <div
          style={{
            position: "absolute",
            top: 120,
            left: 50,
            width: 500,
            height: 300,
            background: "rgba(255,255,255,0.95)",
            padding: "10px",
            borderRadius: "8px",
            boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
            zIndex: 1000,
          }}
        >
          <ResponsiveContainer width="100%" height="100%">
            <LineChart data={history}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="time" />
              <YAxis />
              <ChartTooltip />
              <Legend />
              <Line type="monotone" dataKey="Running" stroke="green" />
              <Line type="monotone" dataKey="Ghost" stroke="red" />
              <Line type="monotone" dataKey="Anomaly" stroke="orange" />
            </LineChart>
          </ResponsiveContainer>
        </div>
      )}
    </div>
  );
}
